const s=`{% block sw_cms_missing_element_modal %} <sw-modal class="sw-cms-missing-element-modal" variant="small" :title="$t('sw-cms.components.cmsMissingElementModal.headline')" @modal-close="onClose" > {% block sw_cms_missing_element_modal_title %} <p class="sw-cms-missing-element-modal__title" v-html="title" ></p> {% endblock %} {% block sw_cms_missing_element_modal_subtitle %} <p class="sw-cms-missing-element-modal__subtitle"> {{ $t('sw-cms.components.cmsMissingElementModal.subtitle') }} </p> {% endblock %} {% block sw_cms_missing_element_modal_paragraph %} <p class="sw-cms-missing-element-modal__paragraph"> {{ $t('sw-cms.components.cmsMissingElementModal.paragraph') }} </p> {% endblock %} <mt-checkbox class="sw-cms-missing-element-modal__dont-remind" :label="$t('sw-app.component.sw-app-actions.dontAskMeAgain')" @update:checked="onChangeDontRemindCheckbox()" /> <template #modal-footer> {% block sw_cms_missing_element_modal_button_cancel %} <mt-button class="sw-cms-missing-element-modal__button-cancel" size="small" variant="secondary" @click="onClose" > {{ $t('global.default.cancel') }} </mt-button> {% endblock %} {% block sw_cms_missing_element_modal_button_save %} <mt-button class="sw-cms-missing-element-modal__button-save" size="small" variant="primary" @click="onSave" > {{ $t('sw-cms.components.cmsMissingElementModal.buttonSave') }} </mt-button> {% endblock %} </template> </sw-modal> {% endblock %}`,t=Shopware.Component.wrapComponentConfig({template:s,emits:["modal-close","modal-save","modal-dont-remind-change"],props:{missingElements:{type:Array,required:!0,default(){return[]}}},computed:{element(){return this.missingElements.map(e=>this.$t(`sw-cms.elements.${e}.label`)).join(", ")},title(){return this.$t("sw-cms.components.cmsMissingElementModal.title",{element:this.element},this.missingElements.length)}},methods:{onClose(){this.$emit("modal-close")},onSave(){this.$emit("modal-save")},onChangeDontRemindCheckbox(){this.$emit("modal-dont-remind-change")}}});export{t as default};
